import { Grid, IconButton } from "@material-ui/core";
import React from "react";
import EmailIcon from "@mui/icons-material/Email";
import { styled } from "@material-ui/core";
import Paper from "@material-ui/core/Paper";
import InstagramIcon from "@mui/icons-material/Instagram";
import GitHubIcon from "@mui/icons-material/GitHub";
import LinkedInIcon from "@mui/icons-material/LinkedIn";
import Button from "@material-ui/core/Button";
import { makeStyles } from "@material-ui/core/styles";
import "./Home.css";

const useStyles = makeStyles((theme) => ({
  myClassName: {
    backgroundColor: "#EFD26E",
    position: "relative",
    "&:hover": {
      backgroundColor: "green",
    },
  },
}));

const Contact = () => {
  const classes = useStyles();

  return (
    <React.Fragment>
      <div
        style={{
          display: "flex",
          width: "100%",
          height:'100vh',
          flexDirection: "column",
          justifyContent: "space-between",
          backgroundColor: 'black'
        }}
      >
        <div
          style={{
            marginTop: "80px",
            display: "flex",
            width: "50%",
            flexDirection: "column",
            justifyContent: "center",
          }}
        >
          <div
            style={{
              display: "flex",
              justifyContent: "center",
              fontSize: "30px",
              color: "#888",
              fontWeight: "lighter",
            }}
          >
            <div>Get in touch via social media or email</div>
          </div>
          <div
            style={{
              display: "grid",
              justifyContent: "center",
              // flexDirection: "column",
            }}
          >
            <div
              style={{
                flexDirection: "column",
                display: "flex",
                justifySelf: "",
              }}
            >
              <Grid container spacing={6} style={{ paddingTop: "20px" }}>
                <Grid item xs={6}>
                  <span className="icon-contact email">
                    {/* <EmailIcon style={{ width: "60px", height: "60px" }} /> */}
                    <svg
                      xmlns="http://www.w3.org/2000/svg"
                      viewBox="0 0 512 512"
                      width="60px"
                      height="60px"
                    >
                      <rect fill="#fff" rx="15%"></rect>
                      <path
                        fill="#4285f4"
                        d="M158 391V249l-82-63v175q0 30 30 30"
                      ></path>
                      <path
                        fill="#ea4335"
                        d="M154 248l102 77 102-77v-98l-102 77-102-77"
                      ></path>
                      <path
                        fill="#34a853"
                        d="M354 391V249l82-63v175q0 30-30 30"
                      ></path>
                      <path
                        fill="#c5221f"
                        d="M76 188l82 63v-98l-30-23c-27-21-52 0-52 26"
                      ></path>
                      <path
                        fill="#fbbc04"
                        d="M436 188l-82 63v-98l30-23c27-21 52 0 52 26"
                      ></path>
                    </svg>
                    <span
                      style={{
                        lineHeight: "58px",
                        fontSize: "20px",
                        paddingLeft: "20px",
                        color: 'white'
                      }}
                    >
                      Email
                    </span>
                  </span>
                </Grid>
                <Grid item xs={6} style={{ width: "300px" }}>
                  <span className="icon-contact linkedin">
                    {/* <LinkedInIcon style={{ width: "60px", height: "60px" }} /> */}
                    <svg
                      xmlns="http://www.w3.org/2000/svg"
                      width="60px"
                      height="60px"
                      fill="none"
                      viewBox="0 0 48 48"
                    >
                      <circle cx="24" cy="24" r="20" fill="#0077B5"></circle>
                      <path
                        fill="#fff"
                        fillRule="evenodd"
                        d="M18.775 14.284c0 1.245-.948 2.253-2.43 2.253-1.426 0-2.374-1.008-2.344-2.253-.03-1.306.918-2.284 2.372-2.284 1.454 0 2.373.978 2.402 2.284zM14.12 32.819V18.316h4.507v14.502H14.12v.001zM22.24 22.945c0-1.81-.06-3.352-.12-4.627h3.915l.208 1.987h.09c.592-.92 2.075-2.312 4.477-2.312 2.965 0 5.19 1.957 5.19 6.226v8.602h-4.508v-8.037c0-1.87-.652-3.144-2.283-3.144-1.246 0-1.987.86-2.283 1.69-.119.297-.178.711-.178 1.127v8.364h-4.507v-9.876h-.002z"
                        clipRule="evenodd"
                      ></path>
                    </svg>
                    <span
                      style={{
                        lineHeight: "58px",
                        fontSize: "20px",
                        paddingLeft: "20px",
                        color:'white'
                      }}
                    >
                      LinkedIn
                    </span>
                  </span>
                </Grid>
              </Grid>
              <Grid container spacing={6} style={{ paddingTop: "20px" }}>
                <Grid item xs={6}>
                  <span className="icon-contact github">
                    {/* <GitHubIcon style={{ width: "60px", height: "60px" }} /> */}
                    <svg
                      xmlns="http://www.w3.org/2000/svg"
                      width="60px"
                      height="60px"
                      viewBox="0 0 32 32"
                    >
                      <path d="M16 1.375c-8.282 0-14.996 6.714-14.996 14.996 0 6.585 4.245 12.18 10.148 14.195l.106.031c.75.141 1.025-.322 1.025-.721 0-.356-.012-1.3-.019-2.549-4.171.905-5.051-2.012-5.051-2.012a3.995 3.995 0 00-1.653-2.184l-.016-.009c-1.358-.93.105-.911.105-.911a3.151 3.151 0 012.289 1.53l.008.015a3.2 3.2 0 004.383 1.238l-.016.008a3.194 3.194 0 01.949-2.005l.001-.001c-3.33-.375-6.831-1.665-6.831-7.41l-.001-.089c0-1.521.587-2.905 1.547-3.938l-.003.004a5.236 5.236 0 01-.321-1.821c0-.777.166-1.516.465-2.182l-.014.034s1.256-.402 4.124 1.537c1.124-.321 2.415-.506 3.749-.506s2.625.185 3.849.53l-.1-.024c2.849-1.939 4.105-1.537 4.105-1.537.285.642.451 1.39.451 2.177 0 .642-.11 1.258-.313 1.83l.012-.038A5.786 5.786 0 0125.52 15.5l-.001.091v-.005c0 5.761-3.505 7.029-6.842 7.398a3.579 3.579 0 011.011 2.787l.001-.012c0 2.007-.019 3.619-.019 4.106 0 .394.262.862 1.031.712 6.028-2.029 10.292-7.629 10.292-14.226 0-8.272-6.706-14.977-14.977-14.977h-.019.001z"></path>
                    </svg>
                    <span
                      style={{
                        lineHeight: "58px",
                        fontSize: "20px",
                        paddingLeft: "20px",
                        color:'white'
                      }}
                    >
                      GitHub
                    </span>
                  </span>
                </Grid>
                <Grid item xs={6} style={{ width: "300px" }}>
                  <span className="icon-contact insta">
                    <InstagramIcon
                      style={{
                        width: "60px",
                        height: "60px",
                        color: "#F14D75",
                      }}
                    />
                    <span
                      style={{
                        lineHeight: "58px",
                        fontSize: "20px",
                        paddingLeft: "20px",
                      }}
                    >
                      Instagram
                    </span>
                  </span>
                </Grid>
              </Grid>
            </div>
          </div>
        </div>
        <div style={{ width: "50%" }}></div>
      </div>
    </React.Fragment>
  );
};
export default Contact;
